var RangeUtil = function(){};

RangeUtil.prototype.createEqPtRange = function(field, low){
    return new PtRange(field, rangeSign.INCLUDE, rangeOption.EQ, low, "");
};
RangeUtil.prototype.createCpPtRange = function(field, low){
    return new PtRange(field, rangeSign.INCLUDE, rangeOption.CP, "*"+low + "*", "");
};
RangeUtil.prototype.createBtPtRange = function(field, low, high){
    return new PtRange(field, rangeSign.INCLUDE, rangeOption.BT, low, high);
};
RangeUtil.prototype.createNePtRange = function(field, low){
    return new PtRange(field, rangeSign.INCLUDE, rangeOption.NE, low, "");
};
RangeUtil.prototype.createEqStdRange = function(low){
    return new StdRange(rangeSign.INCLUDE, rangeOption.EQ, low, "");
};
RangeUtil.prototype.createNeStdRange = function(low){
    return new StdRange(rangeSign.INCLUDE, rangeOption.NE, low, "");
};
RangeUtil.prototype.createCpStdRange = function(low){
    return new StdRange(rangeSign.INCLUDE, rangeOption.CP, low, "");
};
RangeUtil.prototype.createBtStdRange = function(low, high){
    return new StdRange(rangeSign.INCLUDE, rangeOption.BT, low, high);
};

var rangeOption = {EQ:"EQ", NE: "NE", LT:"LT", LE:"LE", GT: "GT", GE:"GE", CP: "CP", BT: "BT"};

var rangeSign = {INCLUDE:"I", EXCLUDE:"E"};

var PtRange = function(field, sign, option, low, high){
    this.FIELD = field;
    this.SIGN = sign;
    this.OPTION = option;
    this.LOW = low;
    this.HIGH = high;
};
var StdRange = function(sign, option, low, high){
    this.SIGN = sign;
    this.OPTION = option;
    this.LOW = low;
    this.HIGH = high;
};

