    if(mtypbReverseTable[mtypb] && mtypbReverseTable[mtypb][field]){
        parent = mtypbReverseTable[mtypb][field];
    }
    if(!parent){
        return true;
    }
    var parentItem = zlrecpDiv.find("div[data-part-item='X'][name='"+parent.NAME+"']");
    if(parentItem.length == 0){
        return true;
    }
    var pname = parent.NAME;
    var _input = parentItem.find("input[data-save-code='"+pname+"']");
    var _pval = _input.val();
    if(_input.val()){
        var childCfg = findChildByField(parent, field);
        if(childCfg == null || !childCfg.VAL_SCOPE){
            return true;
        }
        if(childCfg.VAL_SCOPE.indexOf(_pval) != -1){
            return true;
        }
        if (!noMsg){
            alert(I18nUtil.getProp('common_js_alert_89', [parentItem.find("span").eq(0).html()]));
        }
        return false;
    }else{
        var attrName = parent.ATTR_VAL;
        if(attrName && _input.attr(attrName)){
            return true;
        }else{
            if (!noMsg){
                alert(I18nUtil.getProp('common_js_alert_90', [parentItem.find("span").eq(0).html()]));
            }
            return false;
        }
    }
    return true;
    //根据字段寻找子部件配置
    function findChildByField(parentCfg, field){
        var item = null;
        var children = parentCfg.CHILDREN;
        if(!children || children.length == 0){
            return item;
        }
        for(var i = 0; i < children.length; i++){
            var child = children[i];
            if(child.NAME == field){
                item = child;
                break;
            }
        }
        return item;
    }
}
//初始化反向配置
PartsLimitController.prototype.reverseConfig = function(){

    var partsLimitTable = this.partsLimitTable;
    var reverseTable = {};
    for(var i in partsLimitTable){
        var item = partsLimitTable[i];
        if(item.ISMUTEX){
            continue;
        }
        var children = item.CHILDREN;
        for(var j = 0; j < children.length; j++){
            var child = children[j];
            reverseTable[child.NAME] = item;
        }
    }
    this.reverseTable = reverseTable;
}

