    var mtypbPartsLimitTable = this.mtypbPartsLimitTable;
    var mtypbReverseTable = {};
    for(var i in mtypbPartsLimitTable){
        var mtypbItem = mtypbPartsLimitTable[i];
        var reverseTable = {};
        for(var k in mtypbItem){
