 * @param kunnr
 * @returns {boolean}
 */
BrandController.prototype.isSpecialStore = function(kunnr){

    var isSpecialStore = false;
    var storeList = this.storeList;
    if(storeList == null){
       return isSpecialStore;
    }
    for(var i = 0; i < storeList.length; i++){
        var store = storeList[i]
        if(store.code == kunnr){
            isSpecialStore = true;
            break;
        }
    }
    return isSpecialStore;
}
